import React, { useState, useEffect } from 'react';
import { useLeads } from '../../layout/Layout/le';
import { StatusBadge, LeadAvatar, ScoreRing, ScoreChip, Spinner, IconButton } from '../ui';
import { PIPELINE_STAGES, formatDate, cn } from '../utils/helpers';

const TABS = ['Overview', 'AI Analysis', 'AI Reply'];

export default function LeadModal({ lead: initialLead, onClose }) {
  const { analyzeLead, generateReply, updateLeadStatus, leads } = useLeads();
  const [tab, setTab] = useState('Overview');
  const [analyzing, setAnalyzing] = useState(false);
  const [replying, setReplying] = useState(false);
  const [copied, setCopied] = useState(false);

  // Keep in sync with context
  const lead = leads.find((l) => l.id === initialLead.id) || initialLead;

  useEffect(() => {
    const handler = (e) => e.key === 'Escape' && onClose();
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [onClose]);

  const handleAnalyze = async () => {
    setAnalyzing(true);
    setTab('AI Analysis');
    try { await analyzeLead(lead.id); } finally { setAnalyzing(false); }
  };

  const handleReply = async () => {
    setReplying(true);
    setTab('AI Reply');
    try { await generateReply(lead.id); } finally { setReplying(false); }
  };

  const handleCopy = () => {
    if (lead.aiReply) {
      navigator.clipboard.writeText(lead.aiReply);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="modal-backdrop" onClick={onClose}>
      <div
        className="bg-white rounded-3xl shadow-modal w-full max-w-2xl max-h-[90vh] flex flex-col animate-slide-up"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-start gap-4 p-6 border-b border-surface-100">
          <LeadAvatar name={lead.name} size="xl" />
          <div className="flex-1 min-w-0">
            <div className="flex items-start justify-between gap-3">
              <div>
                <h2 className="text-xl font-bold text-surface-900">{lead.name}</h2>
                <p className="text-sm text-surface-500 mt-0.5">{lead.jobTitle || 'N/A'} {lead.company ? `· ${lead.company}` : ''}</p>
              </div>
              <div className="flex items-center gap-2">
                <ScoreRing score={lead.score} size={52} />
                <IconButton onClick={onClose} title="Close" className="ml-1">
                  <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </IconButton>
              </div>
            </div>
            <div className="flex items-center gap-2 mt-3">
              <StatusBadge status={lead.pipelineStatus} />
              <ScoreChip score={lead.score} />
              <span className="text-xs text-surface-400">{lead.source}</span>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex gap-0 px-6 border-b border-surface-100">
          {TABS.map((t) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              className={cn(
                'px-4 py-3 text-sm font-medium border-b-2 transition-all',
                tab === t ? 'border-brand-500 text-brand-600' : 'border-transparent text-surface-500 hover:text-surface-900'
              )}
            >
              {t}
            </button>
          ))}
        </div>

        {/* Tab content */}
        <div className="flex-1 overflow-y-auto p-6">
          {tab === 'Overview' && <OverviewTab lead={lead} onStatusChange={updateLeadStatus} />}
          {tab === 'AI Analysis' && <AIAnalysisTab lead={lead} analyzing={analyzing} onAnalyze={handleAnalyze} />}
          {tab === 'AI Reply' && <AIReplyTab lead={lead} replying={replying} onGenerate={handleReply} onCopy={handleCopy} copied={copied} />}
        </div>

        {/* Footer actions */}
        <div className="flex items-center justify-between gap-3 px-6 py-4 border-t border-surface-100 bg-surface-50 rounded-b-3xl">
          <div className="flex gap-2">
            <a href={`mailto:${lead.email}`} className="btn-secondary text-xs py-2">
              <MailIcon />Email
            </a>
            {lead.phone && <a href={`tel:${lead.phone}`} className="btn-secondary text-xs py-2"><PhoneIcon />Call</a>}
          </div>
          <div className="flex gap-2">
            <button onClick={handleAnalyze} disabled={analyzing} className="btn-secondary text-xs py-2 relative">
              {analyzing ? <Spinner size={14} /> : <BrainIcon />}
              {analyzing ? 'Analyzing…' : 'AI Analysis'}
            </button>
            <button onClick={handleReply} disabled={replying} className="btn-primary text-xs py-2">
              {replying ? <Spinner size={14} color="white" /> : <SparklesIcon />}
              {replying ? 'Generating…' : 'Generate Reply'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Overview Tab ──────────────────────────────────────────────────────────────
function OverviewTab({ lead, onStatusChange }) {
  return (
    <div className="space-y-5">
      {/* Contact info */}
      <section>
        <h3 className="label">Contact Info</h3>
        <div className="card p-4 grid grid-cols-2 gap-4">
          {[
            { label: 'Email', value: lead.email, href: `mailto:${lead.email}` },
            { label: 'Phone', value: lead.phone || '—' },
            { label: 'Company', value: lead.company || '—' },
            { label: 'Job Title', value: lead.jobTitle || '—' },
            { label: 'Source', value: lead.source },
            { label: 'Created', value: formatDate(lead.createdAt) },
          ].map(({ label, value, href }) => (
            <div key={label}>
              <p className="text-xs text-surface-400 mb-0.5">{label}</p>
              {href ? (
                <a href={href} className="text-sm font-medium text-brand-600 hover:underline">{value}</a>
              ) : (
                <p className="text-sm font-medium text-surface-800">{value}</p>
              )}
            </div>
          ))}
        </div>
      </section>

      {/* Message */}
      {lead.message && (
        <section>
          <h3 className="label">Message</h3>
          <div className="card p-4">
            <p className="text-sm text-surface-700 leading-relaxed">{lead.message}</p>
          </div>
        </section>
      )}

      {/* Pipeline stage */}
      <section>
        <h3 className="label">Pipeline Stage</h3>
        <div className="grid grid-cols-3 sm:grid-cols-4 gap-2">
          {PIPELINE_STAGES.map((stage) => (
            <button
              key={stage.id}
              onClick={() => onStatusChange(lead.id, stage.id)}
              className={cn(
                'text-xs font-semibold py-2 px-2 rounded-xl border-2 transition-all',
                lead.pipelineStatus === stage.id
                  ? 'border-current'
                  : 'border-transparent bg-surface-50 text-surface-500 hover:bg-surface-100'
              )}
              style={lead.pipelineStatus === stage.id ? { color: stage.color, backgroundColor: stage.bg, borderColor: stage.dot } : {}}
            >
              {stage.label}
            </button>
          ))}
        </div>
      </section>
    </div>
  );
}

// ── AI Analysis Tab ───────────────────────────────────────────────────────────
function AIAnalysisTab({ lead, analyzing, onAnalyze }) {
  if (analyzing) return <AILoading label="Analyzing lead quality…" />;

  if (!lead.aiAnalysis) {
    return (
      <div className="flex flex-col items-center justify-center py-16 text-center">
        <div className="w-16 h-16 rounded-2xl bg-brand-50 flex items-center justify-center text-3xl mb-4">🧠</div>
        <h3 className="text-base font-semibold text-surface-800 mb-2">Run AI Analysis</h3>
        <p className="text-sm text-surface-400 max-w-xs mb-6">Get instant insights on lead quality, decision power, pain points, and recommended next actions.</p>
        <button onClick={onAnalyze} className="btn-primary">
          <BrainIcon /> Analyze This Lead
        </button>
      </div>
    );
  }

  // Parse markdown-ish analysis into sections
  const lines = lead.aiAnalysis.split('\n').filter(Boolean);
  return (
    <div className="space-y-3">
      <div className="flex items-center gap-2 mb-4">
        <span className="text-green-500 text-sm">●</span>
        <span className="text-xs text-surface-500 font-medium">Analysis complete · AI-powered insights</span>
      </div>
      <div className="card p-4 bg-surface-50 border-0">
        <div className="space-y-2">
          {lines.map((line, i) => {
            const isBold = line.startsWith('**');
            if (isBold) {
              const [boldPart, ...rest] = line.split('**').filter(Boolean);
              return (
                <div key={i} className="flex gap-2 py-1 border-b border-surface-100 last:border-0">
                  <span className="text-xs font-bold text-surface-700 w-36 flex-shrink-0">{boldPart.replace(/:$/, '')}:</span>
                  <span className="text-sm text-surface-700">{rest.join('').replace(/^: /, '')}</span>
                </div>
              );
            }
            return <p key={i} className="text-sm text-surface-600 leading-relaxed pl-1">{line.replace(/^- /, '• ')}</p>;
          })}
        </div>
      </div>
      <button onClick={onAnalyze} className="btn-ghost text-xs">↺ Regenerate</button>
    </div>
  );
}

// ── AI Reply Tab ──────────────────────────────────────────────────────────────
function AIReplyTab({ lead, replying, onGenerate, onCopy, copied }) {
  if (replying) return <AILoading label="Crafting personalized reply…" />;

  if (!lead.aiReply) {
    return (
      <div className="flex flex-col items-center justify-center py-16 text-center">
        <div className="w-16 h-16 rounded-2xl bg-brand-50 flex items-center justify-center text-3xl mb-4">✉️</div>
        <h3 className="text-base font-semibold text-surface-800 mb-2">Generate AI Reply</h3>
        <p className="text-sm text-surface-400 max-w-xs mb-6">Get a personalized, sales-optimized email reply crafted for this specific lead's context and intent.</p>
        <button onClick={onGenerate} className="btn-primary">
          <SparklesIcon /> Generate Reply
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-green-500 text-sm">●</span>
          <span className="text-xs text-surface-500 font-medium">AI-generated reply · Ready to send</span>
        </div>
        <div className="flex gap-2">
          <button onClick={onCopy} className={cn('btn-secondary text-xs py-1.5', copied && 'text-success-700 border-success-200')}>
            {copied ? '✓ Copied!' : '📋 Copy'}
          </button>
          <button onClick={onGenerate} className="btn-ghost text-xs">↺ Regenerate</button>
        </div>
      </div>
      <div className="card p-5 bg-surface-50 border-0">
        <div className="text-sm text-surface-700 leading-relaxed whitespace-pre-line font-sans">
          {lead.aiReply}
        </div>
      </div>
      <a
        href={`mailto:${lead.email}?body=${encodeURIComponent(lead.aiReply)}`}
        className="btn-primary w-full justify-center"
      >
        <MailIcon /> Send via Email Client
      </a>
    </div>
  );
}

// ── AI Loading State ──────────────────────────────────────────────────────────
function AILoading({ label }) {
  return (
    <div className="flex flex-col items-center justify-center py-20 gap-4">
      <div className="relative w-16 h-16">
        <div className="absolute inset-0 rounded-full border-4 border-brand-100 animate-ping opacity-50" />
        <div className="w-16 h-16 rounded-full bg-brand-50 flex items-center justify-center">
          <Spinner size={24} color="#4f6ef7" />
        </div>
      </div>
      <p className="text-sm text-surface-500 font-medium">{label}</p>
    </div>
  );
}

// ── Tiny Icons ────────────────────────────────────────────────────────────────
function MailIcon() {
  return <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>;
}
function PhoneIcon() {
  return <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z" /></svg>;
}
function BrainIcon() {
  return <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" /></svg>;
}
function SparklesIcon() {
  return <svg width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" /></svg>;
}
